define i8 @ashr_add_exact(i8 %amt_in, i8 %cnt_in) {
  %amt = and i8 %amt_in, -14
  %cnt = and i8 %cnt_in, 1
  %r = ashr i8 %amt, %cnt
  ret i8 %r
}

